const seenW2 = new Set();
const vocabFinal = [];
for (const v of vocabAll) {
  const key = v.w.toLowerCase();
  if (!seenW2.has(key)) {
    seenW2.add(key);
    vocabFinal.push(v);
  }
}
console.log('Vocab final count:', vocabFinal.length);

const words = vocabFinal.slice(0, 950).map((v, i) => ({
  id: i + 1,
  word: v.w,
  hindi: v.h,
  simpleMeaning: v.sm,
  ipa: v.ipa,
  verbForms: v.vf,
  synonyms: v.syn,
  antonyms: v.ant,
  sentences: v.sen,
  usageNote: v.un,
  cefrLevel: v.cl
}));

