const buildTranslate = (hindi, answer, distractors) => ({
  type: "translate",
  hindi,
  options: [
    ...distractors.map(d => ({english: d.e, hindi: d.h})),
    answer
  ].sort(() => Math.random() - 0.5),
  answer,
  explanation: `Correct translation: "${hindi}" = "${answer}"`
});

const buildFill = (sentence, answer, distractors, explanation) => ({
  type: "fill",
  sentence,
  options: [answer, ...distractors].sort(() => Math.random() - 0.5),
  answer,
  explanation: explanation || `The missing word is "${answer}" — full sentence: "${sentence.replace('_____', answer)}"`
});

const buildError = (wrong, correct, explanation) => ({
  type: "error",
  sentence: wrong,
  options: [wrong, correct],
  answer: correct,
  explanation: explanation || `Correct sentence: "${correct}". The version shown had a grammar mistake.`
});

const buildMCQ = (question, answer, distractors, explanation) => ({
  type: "mcq",
  sentence: question,
  options: [answer, ...distractors].sort(() => Math.random() - 0.5),
  answer,
  explanation
});

